<div class="page-title-row"><div><p class="text-muted mb-1">Credentials & compliance</p><h1>Certification Approval Center</h1></div><a class="btn btn-outline-primary" href="/portal/certifications"><i class="fa-solid fa-certificate me-2"></i>All certifications</a></div>
<section class="portal-card"><div class="table-responsive"><table class="table portal-table align-middle"><thead><tr><th>Employee</th><th>Certification</th><th>Target</th><th>Status</th><th>Evidence</th><th>Decision</th></tr></thead><tbody><?php foreach($renewals as $r):?><tr><td><?=e($r['employee_name'])?></td><td><strong><?=e($r['certification_name'])?></strong><div class="small text-muted">Expires <?=e($r['expires_date']?:'N/A')?></div></td><td><?=e($r['target_date']?:'Not set')?></td><td><span class="badge text-bg-<?=$r['status']==='approved'?'success':($r['status']==='rejected'?'danger':'secondary')?>"><?=e($r['status'])?></span></td><td><?php foreach($attachments[$r['id']]??[] as $a):?><div><a href="/portal/certification-approval-attachments/<?=$a['id']?>"><i class="fa-solid fa-paperclip me-1"></i><?=e($a['filename'])?></a></div><?php endforeach?><form class="mt-2" method="post" enctype="multipart/form-data" action="/portal/certification-approvals/<?=$r['id']?>/attachments"><?=csrf_field()?><input class="form-control form-control-sm mb-1" type="file" name="document" accept="application/pdf,image/jpeg,image/png" required><button class="btn btn-sm btn-outline-primary">Upload</button></form></td><td><?php if(in_array($r['status'],['submitted','requested','in_progress'],true)):?><form method="post" action="/portal/certification-approvals/<?=$r['id']?>/decide"><?=csrf_field()?><textarea class="form-control form-control-sm mb-2" name="decision_notes" placeholder="Decision notes"></textarea><div class="btn-group"><button class="btn btn-sm btn-success" name="status" value="approved">Approve</button><button class="btn btn-sm btn-outline-danger" name="status" value="rejected">Reject</button></div></form><?php else:?><div><?=e($r['decision_notes']?:'No decision notes')?></div><small class="text-muted"><?=e($r['decided_name']??'')?> <?=e($r['decided_at']??'')?></small><?php endif?></td></tr><?php endforeach?><?php if(empty($renewals)):?><tr><td colspan="6" class="text-center text-muted py-5">No renewal approvals are waiting.</td></tr><?php endif?></tbody></table></div></section>
